module top_module(
  input clk,
  input reset,
  input [7:0] data,
  output reg match
);reg [7:0] unused_prev_data;

always @(posedge clk or posedge reset) begin
  if (reset) begin
    match <= 0;
    unused_prev_data <= 0;
  end else begin
    if (data > unused_prev_data) begin
      match <= 1;
    end else begin
      match <= 0;
    end
    unused_prev_data <= data;
  end
end

endmodule
